# Feature Store: eliminate training-serving skew
class FeatureStore:
    def __init__(self, online_store, offline_store):
        self.online = online_store   # Redis for real-time inference
        self.offline = offline_store  # BigQuery for training

    def get_features(self, entity_key, feature_names, point_in_time=None):
        """Point-in-time correct retrieval for training"""
        if point_in_time:
            return self.offline.query_as_of(entity_key, feature_names, point_in_time)
        return self.online.get(entity_key, feature_names)

    def compute_features(self, raw_data):
        """Single implementation — used in both batch and online"""
        features = {}
        features["avg_7d"] = raw_data.rolling(7).mean()
        from scipy.stats import zscore
        features["z_score"] = zscore(raw_data)
        return features

def detect_drift(training_dist, serving_dist, threshold=0.05):
    from scipy.stats import ks_2samp
    stat, p_value = ks_2samp(training_dist, serving_dist)
    if p_value < threshold:
        alert("Data drift detected! Triggering retraining...")
    return stat, p_value
